{
  "name": "DC State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; prioritizes people with limited incomes but open to all Medicare beneficiaries, families, and caregivers[1][3]",
    "asset_limits": "No asset limits or tests apply[1]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver living in the District of Columbia[1][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one personalized health insurance counseling, education, and assistance on Medicare (Parts A, B, C, D), Medigap, Medicaid, Medicare Savings Programs, Extra Help/Low Income Subsidy, federal retiree benefits, durable medical equipment, billing issues; group educational presentations, outreach at community events, and Senior Medicare Patrol services to prevent fraud[1][3][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: (202) 727-8370[2][4][5]", "Email: ship.dacl@dc.gov[2][4][5]", "Website: https://dacl.dc.gov/service/health-insurance-counseling[2][3]", "In-person: DC Dept. of Aging and Community Living, 250 E Street SW, Washington DC 20024 (hours 9:00 am - 5:00 pm)[2][4]"],
    "processing_time": "No formal application or processing time; services provided directly upon contact[1][3][4]",
    "waitlist": null,
    "forms": ["No specific forms required; counselors assist directly[1][4]"],
    "documents": ["Medicare card, current insurance details, billing statements if applicable (recommended but not mandatory)[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "District of Columbia residents only[2][3]",
    "regional_variations": null,
    "offices_or_providers": ["Primary office: DC Dept. of Aging and Community Living (DACL), 250 E Street SW, Washington DC 20024; delivered statewide via partnerships with local agencies[1][2]"]
  },
  "official_source": "https://dacl.dc.gov/service/health-insurance-counseling",
  "gotchas": ["Not a financial aid or healthcare provider program—only free counseling and education, no direct payments or medical services; services are unbiased and do not sell plans; prioritizes limited-income and dually eligible but open to all; increasing demand may affect availability despite no waitlist[1][3][6]"],
  "data_shape_notes": "no income or asset test; counseling-only service for Medicare beneficiaries; single centralized DC provider via DACL with phone/email/in-person access"
}

{
  "name": "DACL Senior Wellness Centers",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits identified; open to DC residents age 60+ without mention of financial thresholds in program descriptions[3][5][6]",
    "asset_limits": "No asset limits specified for Senior Wellness Centers[3][5][6]",
    "other_requirements": ["District of Columbia resident[3][5][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Comprehensive programs promoting health and wellness, including health activities, social activities, nutrition services, trips, and events; typically available Monday-Friday 8:00 AM-5:00 PM (varies slightly by center); programming offered virtually and in-person[3][5]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact specific center directly by phone to sign up for activities and trips (e.g., Bernice Fonteneau: (202) 727-0338; Model Cities: (202) 635-1900; Hayes: (202) 727-0357; Congress Heights: (202) 563-7225); Call DACL Information and Referral Assistance (I&R/A) line for general intake and screening; Visit centers in-person or check event calendars on center websites[2][5]"],
    "processing_time": "No formal processing time; direct sign-up for activities, no enrollment or re-certification required for trips and programs[2]",
    "waitlist": "No waitlist mentioned; expansions at some centers (e.g., Model Cities, Congress Heights) to increase capacity[2][3]",
    "forms": ["No specific forms required for general participation; enrollment applications may be used for related programs like trips via I&R/A or ConnectorCard via Seabury[2]"],
    "documents": ["No documents specified for basic participation; DC residency verification may be needed informally[6]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "District of Columbia only",
    "regional_variations": "Six centers across Wards 1,4,5,6,7,8 with different operators, phone numbers, hours (e.g., 8:30AM-4PM vs 8AM-5PM), websites, and event calendars; programming modes vary (e.g., Hayes in-person Tue-Thu, virtual Mon); expansions in Wards 5 and 8[2][3][5]",
    "offices_or_providers": ["Ward 1: Bernice Fonteneau Senior Wellness Center, 3531 Georgia Ave NW, (202) 727-0338; Ward 5: Model Cities Senior Wellness Center, 1901 Evarts St NE, (202) 635-1900, www.seaburyresources.org/model-cities-senior-wellness-center; Ward 6: Hayes Senior Wellness Center, 500 K St NE, (202) 727-0358, www.hayesswc.com; Ward 7: Washington Seniors Wellness Center; Ward 8: Congress Heights Senior Wellness Center, 3500 MLK Jr Ave SE, (202) 563-7225[5]"]
  },
  "official_source": "https://dacl.dc.gov/service/senior-centers",
  "gotchas": ["Not a Medicaid waiver program (confused with EPD Waiver which has strict income <$2,382/mo, assets <$4,000, age 65+ or disabled); no formal eligibility screening or income test—direct center contact; availability limited to specific wards/centers, not citywide; primarily drop-in wellness/social, not medical care or home assistance[1][3][5][6]", "Expansions ongoing at select centers may affect capacity[2][3]"],
  "data_shape_notes": "Ward-specific centers with direct sign-up, no income/asset test, open to age 60+ DC residents; separate from stricter EPD Waiver program"
}

{
  "name": "Legal Services for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits stated for AARP Legal Counsel for the Elderly (LCE) or DACL program; prioritizes those with economic or social needs. Related programs like Legal Aid DC use 200-300% of Federal Poverty Guidelines, but not explicitly tied here[1][2][4].",
    "asset_limits": "No asset limits mentioned in sources[1][2].",
    "other_requirements": ["Must be DC resident", "For LCE Legal Hotline: DC residents 60+ or 55+ with Social Security/SSI disability issues[2]", "Targeted to older individuals with economic or social needs per OAA guidelines[3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice, assistance, referrals, and representation by attorneys/paralegals in: victims of abuse, medical bills, advocacy, public benefits (SS/SSI/SSDI, Medicaid, Medicare, veterans benefits), drafting wills, conservatorship/guardianship, housing/eviction/foreclosure, long-term care access, elder abuse/financial exploitation, tenant advocacy, notary services[1][2][3].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Phone: AARP LCE (202) 434-2120[1][2]",
      "Phone: DACL/DC Office on Aging (202) 724-5626 or TTY 711[1]",
      "Website: AARP LCE https://www.aarp.org/legal-counsel-for-elderly/[1][2]",
      "LCE Legal Hotline for advice/referrals/intake[2]",
      "DC Resource Bridge referral: 202-933-HELP[4][5]"
    ],
    "processing_time": "Not specified; LCE hotline provides quick access to advice/referrals/intake[2].",
    "waitlist": null,
    "forms": ["No specific form names/numbers listed; online intake for related Legal Aid DC[4]"],
    "documents": ["Documents related to legal problem if available (e.g., for upload in related online intakes)[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "District of Columbia residents only[1][2]",
    "regional_variations": null,
    "offices_or_providers": [
      "AARP Legal Counsel for the Elderly: 601 E Street, NW, Room A-4, Washington, DC 20049[1]",
      "DC Office on Aging Notary: 500 K Street, NE, Washington, DC 20002[1]"
    ]
  },
  "official_source": "https://dacl.dc.gov/service/legal-services-seniors[1]",
  "gotchas": [
    "No explicit income/asset dollar limits for core LCE/DACL services, unlike some related programs (e.g., Legal Aid DC at 200-300% FPG)[4]; eligibility focuses on age, residency, and needs[1][2][3]",
    "Services via hotline or specific providers; may need referral through DC Resource Bridge for broader help[4][5]",
    "Targeted representation not guaranteed for all issues; often advice/referrals first[2]"
  ],
  "data_shape_notes": "No income/asset tests specified; age/residency-based with needs priority; delivered via specific DC providers/hotlines under OAA framework[1][2][3]"
}

